// src/contexts/WebSocket/WebSocket/useMediaStream.ts
import { useCallback, useRef } from 'react';
import type { SFUManager } from '@/lib/SFUManager';

interface UseMediaStreamParams {
  sfuManagerRef: React.MutableRefObject<SFUManager | null>;
  setLocalStream: (stream: MediaStream | null) => void;
  setLocalScreenStream: (stream: MediaStream | null) => void;
  setIsAudioEnabled: (enabled: boolean) => void;
  setIsVideoEnabled: (enabled: boolean) => void;
  setIsScreenSharing: (sharing: boolean) => void;
  setIsMediaLoading: (loading: boolean) => void;
}

// Media sources we register in SFUManager
const VIDEO_SOURCE = 'webcam';
const AUDIO_SOURCE = 'mic';
const SCREEN_SOURCE = 'screen';

export function useMediaStream({
  sfuManagerRef,
  setLocalStream,
  setLocalScreenStream,
  setIsAudioEnabled,
  setIsVideoEnabled,
  setIsScreenSharing,
  setIsMediaLoading,
}: UseMediaStreamParams) {
  const localStreamRef = useRef<MediaStream | null>(null);
  const screenStreamRef = useRef<MediaStream | null>(null);
  const audioEnabledRef = useRef(false);
  const videoEnabledRef = useRef(false);
  const screenSharingRef = useRef(false);

  /** Attach current local tracks to SFU producers */
  const attachLocalToSFU = useCallback(
    async (stream: MediaStream | null) => {
      const sfu = sfuManagerRef.current;
      if (!sfu || !stream) return;

      const videoTrack = stream.getVideoTracks()[0];
      const audioTrack = stream.getAudioTracks()[0];

      console.log('[useMediaStream] attachLocalToSFU', {
        hasStream: !!stream,
        videoTracks: stream.getVideoTracks().length,
        audioTracks: stream.getAudioTracks().length,
        videoTrackId: videoTrack?.id,
        audioTrackId: audioTrack?.id,
      });

      try {
        if (videoTrack) {
          await sfu.replaceTrack(videoTrack, VIDEO_SOURCE);
          videoEnabledRef.current = true;
          setIsVideoEnabled(true);
        }
        if (audioTrack) {
          await sfu.replaceTrack(audioTrack, AUDIO_SOURCE);
          audioEnabledRef.current = true;
          setIsAudioEnabled(true);
        }
      } catch (err: unknown) {
        console.error('[useMediaStream] Failed to attach local tracks to SFU', err);
      }
    },
    [sfuManagerRef, setIsAudioEnabled, setIsVideoEnabled],
  );

  /** Start / restart camera + mic */
  const enableMedia = useCallback(async () => {
    console.log('[useMediaStream] enableMedia called');
    setIsMediaLoading(true);

    try {
      // Close old stream if any
      if (localStreamRef.current) {
        localStreamRef.current.getTracks().forEach((t) => t.stop());
        localStreamRef.current = null;
      }

      const constraints: MediaStreamConstraints = {
        audio: true,
        video: {
          width: { ideal: 1280 },
          height: { ideal: 720 },
          frameRate: { ideal: 30 },
        },
      };

      const stream = await navigator.mediaDevices.getUserMedia(constraints);

      console.log('[useMediaStream] gotUserMedia', {
        videoTracks: stream.getVideoTracks().map((t) => ({
          id: t.id,
          readyState: t.readyState,
          enabled: t.enabled,
          label: t.label,
        })),
        audioTracks: stream.getAudioTracks().map((t) => ({
          id: t.id,
          readyState: t.readyState,
          enabled: t.enabled,
          label: t.label,
        })),
      });

      localStreamRef.current = stream;
      setLocalStream(stream);

      await attachLocalToSFU(stream);
    } catch (err: unknown) {
      console.error('[useMediaStream] enableMedia failed', err);
      setLocalStream(null);
      setIsAudioEnabled(false);
      setIsVideoEnabled(false);
      audioEnabledRef.current = false;
      videoEnabledRef.current = false;
    } finally {
      setIsMediaLoading(false);
    }
  }, [attachLocalToSFU, setIsAudioEnabled, setIsVideoEnabled, setIsMediaLoading, setLocalStream]);

  /** Toggle camera on/off */
  const toggleVideo = useCallback(async () => {
    const stream = localStreamRef.current;
    const sfu = sfuManagerRef.current;

    // Guard against missing SFU
    if (!sfu) {
      console.warn('[useMediaStream] toggleVideo called but SFU not ready');
      return;
    }

    if (!stream) {
      // If no stream yet, just enable media fresh
      console.log('[useMediaStream] toggleVideo -> no stream, enabling media');
      await enableMedia();
      return;
    }

    const videoTrack = stream.getVideoTracks()[0];
    const currentlyEnabled = !!videoTrack && videoTrack.enabled;

    if (currentlyEnabled) {
      console.log('[useMediaStream] toggleVideo -> OFF - stopping camera');
      // Stop the track to release camera hardware
      videoTrack.stop();
      // Remove the track from the stream
      stream.removeTrack(videoTrack);
      setIsVideoEnabled(false);
      videoEnabledRef.current = false;
      // Close the producer completely
      await sfu.closeProducer(VIDEO_SOURCE);
    } else {
      console.log('[useMediaStream] toggleVideo -> ON - acquiring camera');
      // Always re-acquire camera when turning on
      try {
        const camStream = await navigator.mediaDevices.getUserMedia({
          video: {
            width: { ideal: 1280 },
            height: { ideal: 720 },
            frameRate: { ideal: 30 },
          },
          audio: false,
        });
        const newVideoTrack = camStream.getVideoTracks()[0];
        if (newVideoTrack) {
          stream.addTrack(newVideoTrack);
          await sfu.replaceTrack(newVideoTrack, VIDEO_SOURCE);
          setIsVideoEnabled(true);
          videoEnabledRef.current = true;
        }
      } catch (err: unknown) {
        console.error('[useMediaStream] Failed to enable video', err);
      }
    }
  }, [enableMedia, sfuManagerRef, setIsVideoEnabled]);

  /** Toggle mic on/off */
  const toggleAudio = useCallback(async () => {
    const stream = localStreamRef.current;
    const sfu = sfuManagerRef.current;

    // Guard against missing SFU
    if (!sfu) {
      console.warn('[useMediaStream] toggleAudio called but SFU not ready');
      return;
    }

    if (!stream) {
      console.log('[useMediaStream] toggleAudio -> no stream, enabling media');
      await enableMedia();
      return;
    }

    const audioTrack = stream.getAudioTracks()[0];
    const currentlyEnabled = !!audioTrack && audioTrack.enabled;

    if (currentlyEnabled) {
      console.log('[useMediaStream] toggleAudio -> OFF - stopping microphone');
      // Stop the track to release microphone hardware
      audioTrack.stop();
      // Remove the track from the stream
      stream.removeTrack(audioTrack);
      setIsAudioEnabled(false);
      audioEnabledRef.current = false;
      // Close the producer completely
      await sfu.closeProducer(AUDIO_SOURCE);
    } else {
      console.log('[useMediaStream] toggleAudio -> ON - acquiring microphone');
      // Always re-acquire microphone when turning on
      try {
        const micStream = await navigator.mediaDevices.getUserMedia({
          audio: true,
          video: false,
        });
        const newAudioTrack = micStream.getAudioTracks()[0];
        if (newAudioTrack) {
          stream.addTrack(newAudioTrack);
          await sfu.replaceTrack(newAudioTrack, AUDIO_SOURCE);
          setIsAudioEnabled(true);
          audioEnabledRef.current = true;
        }
      } catch (err: unknown) {
        console.error('[useMediaStream] Failed to enable audio', err);
      }
    }
  }, [enableMedia, sfuManagerRef, setIsAudioEnabled]);

  /** Start screen share */
  const startScreenShare = useCallback(async () => {
    if (screenSharingRef.current) return;

    const sfu = sfuManagerRef.current;
    if (!sfu) return;

    try {
      console.log('[useMediaStream] startScreenShare');
      const displayStream = await navigator.mediaDevices.getDisplayMedia({
        video: true,
        audio: false,
      });

      screenStreamRef.current = displayStream;
      setLocalScreenStream(displayStream);
      setIsScreenSharing(true);
      screenSharingRef.current = true;

      const videoTrack = displayStream.getVideoTracks()[0];
      if (videoTrack) {
        await sfu.replaceTrack(videoTrack, SCREEN_SOURCE);
      }

      // When user stops sharing from browser UI
      videoTrack.onended = () => {
        console.log('[useMediaStream] screen track ended');
        stopScreenShare();
      };
    } catch (err: unknown) {
      console.error('[useMediaStream] startScreenShare failed', err);
      setLocalScreenStream(null);
      setIsScreenSharing(false);
      screenSharingRef.current = false;
    }
  }, [sfuManagerRef, setIsScreenSharing, setLocalScreenStream]);

  /** Stop screen share */
  const stopScreenShare = useCallback(() => {
    console.log('[useMediaStream] stopScreenShare');
    const sfu = sfuManagerRef.current;

    if (screenStreamRef.current) {
      screenStreamRef.current.getTracks().forEach((t) => t.stop());
      screenStreamRef.current = null;
    }

    setLocalScreenStream(null);
    setIsScreenSharing(false);
    screenSharingRef.current = false;

    // Close screen producer on SFU
    sfu?.closeProducer(SCREEN_SOURCE);
  }, [sfuManagerRef, setIsScreenSharing, setLocalScreenStream]);

  return {
    enableMedia,
    toggleAudio,
    toggleVideo,
    startScreenShare,
    stopScreenShare,
  };
}
